{{CSS|content=@import url('https://fonts.googleapis.com/css2?family=Rubik:wght@300;500;700&family=Playfair+Display:wght@400;700&family=UnifrakturMaguntia&display=swap');

:root {
  --tv-black: 18, 24, 40;
  --tv-grey: 70, 80, 110;
  --tv-lightgrey: 160, 170, 190;
  --tv-yellow: 170, 150, 255;
  --tv-gold: 200, 190, 255;
  --tv-white: 245, 248, 255;
  --tv-shadow: 0, 0, 0;

  --body-font: 'Rubik', sans-serif;
  --holy-font: 'Playfair Display', serif;
  --title-font: 'UnifrakturMaguntia', cursive;
  --mono-font: 'Fantasque Sans Mono', monospace;
}

.page-container .page {
  border: 3px solid rgba(var(--tv-gold), 0.85);
  margin: 12px auto;
  border-radius: 22px;
  box-shadow: 
    0 0 25px rgba(var(--tv-yellow), 0.45),
    inset 0 0 15px rgba(var(--tv-gold), 0.35),
    0 0 40px rgba(0, 0, 0, 0.6);
  background: linear-gradient(
    135deg,
    rgba(var(--tv-black), 0.96),
    rgba(var(--tv-grey), 0.8),
    rgba(180, 170, 255, 0.12)
  );
  background-image:
    repeating-linear-gradient(0deg, rgba(var(--tv-white), 0.05) 0px, transparent 3px, transparent 6px);
  backdrop-filter: blur(4px);
}

.theme-fandomdesktop-dark {
  --theme-page-background-color: rgba(var(--tv-black), 0.95);
  --theme-page-background-color--secondary: rgba(var(--tv-grey), 0.7);
  --theme-link-color: rgb(var(--tv-gold));
  --theme-border-color: rgba(var(--tv-yellow), 0.9);
  --theme-community-header-color: rgb(var(--tv-gold));
  --theme-sticky-nav-background-color: rgba(var(--tv-black), 0.96);
  --theme-sticky-nav-text-color: rgb(var(--tv-yellow));
  --theme-sticky-nav-text-color--hover: rgb(220, 215, 255);
}

.theme-fandomdesktop-light {
  --theme-page-background-color: rgba(235, 240, 255, 0.92);
  --theme-page-background-color--secondary: rgba(var(--tv-black), 0.85);
  --theme-link-color: rgb(40, 45, 70);
  --theme-border-color: rgba(var(--tv-yellow), 0.85);
  --theme-community-header-color: rgb(var(--tv-gold));
  --theme-sticky-nav-background-color: rgba(235, 240, 255, 0.95);
  --theme-sticky-nav-text-color: rgb(var(--tv-black));
  --theme-sticky-nav-text-color--hover: rgb(var(--tv-yellow));
}

a,
a:visited {
  color: rgb(var(--tv-gold)) !important;
  text-decoration: none;
  transition: color 0.4s ease, text-shadow 0.4s ease;
}

a:hover,
a:focus {
  color: rgb(var(--tv-yellow)) !important;
  text-shadow: 
    0 0 8px rgba(var(--tv-yellow), 0.95),
    0 0 18px rgba(var(--tv-gold), 0.7);
}

.page-side-tools .page-side-tool {
  border: 2px solid rgba(var(--tv-yellow), 0.9);
  box-shadow: 0 0 15px rgba(var(--tv-gold), 0.5);
  border-radius: 50%;
  background-color: rgba(var(--tv-black), 0.88);
  transition: transform 0.4s ease, box-shadow 0.4s ease;
}

.page-side-tool:hover {
  transform: scale(1.12) rotate(4deg);
  box-shadow: 0 0 25px rgba(var(--tv-yellow), 0.85);
}

.titleblock,
.dark-titleblock {
  background: radial-gradient(circle at top, rgba(var(--tv-yellow), 0.25), rgba(var(--tv-black), 0.96));
  border: 3px solid rgba(var(--tv-gold), 0.85);
  border-radius: 28px;
  padding: 1.2rem 1.8rem;
  font-family: var(--title-font);
  font-weight: 700;
  color: rgb(var(--tv-gold));
  text-shadow: 
    0 0 8px rgba(var(--tv-yellow), 1),
    0 0 20px rgba(var(--tv-gold), 0.8),
    2px 2px 4px rgba(0, 0, 0, 0.6);
  font-size: 2.6em;
  letter-spacing: 3px;
  transform: rotate(-1.5deg);
  animation: holy-glow 3s infinite alternate ease-in-out;
}

.progress {
  background: rgba(var(--tv-black), 0.92);
  border: 2px solid rgba(var(--tv-gold), 0.8);
  border-radius: 18px;
  color: rgb(var(--tv-white));
  box-shadow: 0 0 12px rgba(var(--tv-yellow), 0.5);
}

.progress .bar {
  background: linear-gradient(to right, rgb(var(--tv-gold)), rgb(var(--tv-yellow)));
  border-radius: 14px;
  box-shadow: 0 0 18px rgba(var(--tv-yellow), 0.9);
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--holy-font);
  color: rgb(var(--tv-gold));
  text-transform: uppercase;
  letter-spacing: 3px;
  text-shadow: 
    0 0 8px rgba(var(--tv-yellow), 0.95),
    0 0 20px rgba(var(--tv-gold), 0.75);
  font-size: calc(1.55rem + 0.7vw);
}

h1 {
  font-size: calc(2.4rem + 1.3vw);
}

@keyframes holy-glow {
  0%, 100% {
    opacity: 1;
    text-shadow: 
      0 0 10px rgba(var(--tv-yellow), 1),
      0 0 25px rgba(var(--tv-gold), 0.9),
      0 0 40px rgba(200, 190, 255, 0.4);
  }
  50% {
    opacity: 0.92;
    text-shadow: 
      0 0 6px rgba(var(--tv-yellow), 0.8),
      0 0 18px rgba(var(--tv-gold), 0.6);
  }
}
}}

